import sys

def read():
    return sys.stdin.readline().strip()

def read_int():
    return int(read())

def read_ints():
    return [int(x) for x in read().split()]

def solve(n,a):
    t=0
    cost=0
    for i in range(n):
        if abs(a[i]-t)>1:
            cost+=abs(a[i]-t)
        t+=1
    return t,cost

def main():
    n=read_int()
    a=read_ints()
    t,cost=solve(n,a)
    print(t,cost)

if __name__ == "__main__":
    main()
